using System;
using DoHoa.CustomMenu;
using Xmap;
namespace DoHoa;

public class GraphicsManagement : IActionListener
{
	private static GraphicsManagement _Instance;

	public static bool HienThiLogo;

	public static bool HienThiBackground;

	public static bool isShowCharsInMap;

	public static bool isHuntingBoss;

	public static bool MapLuoi;

	public static mFont DrawFont;

	public static Image imgCheck;

	public static Image imgTheBai;

	private static string StringTheBai70x70;

	private static string StringTheBai30x30;

	private static string StringTheBai100x100;

	public static string Logo;

	public static string logoPixel;

	public static string logoCuongLe;

	public static bool paintBoxMobReduceCPU;

	public static bool paintInventoryReduceCPU;

	public static GraphicsManagement getInstance()
	{
		if (_Instance == null)
		{
			_Instance = new GraphicsManagement();
		}
		return _Instance;
	}

	public static void Update()
	{
	}

	public static void Paint(mGraphics g)
	{
		if (!MainMenu.isShowMenuVIP)
		{
			g.drawImage(imgTheBai, 160, 3);
		}
	}

	public void perform(int idAction, object p)
	{
		switch (idAction)
		{
		case 1:
			HienThiLogo = !HienThiLogo;
			Rms.saveRMSInt("saveLogo", HienThiLogo ? 1 : 0);
			break;
		case 2:
			HienThiBackground = !HienThiBackground;
			Rms.saveRMSInt("saveBackground", HienThiBackground ? 1 : 0);
			break;
		case 3:
			isHuntingBoss = !isHuntingBoss;
			Rms.saveRMSInt("sanboss", isHuntingBoss ? 1 : 0);
			break;
		case 4:
			isShowCharsInMap = !isShowCharsInMap;
			Rms.saveRMSInt("showchar", isShowCharsInMap ? 1 : 0);
			break;
		case 5:
			MapLuoi = !MapLuoi;
			Rms.saveRMSInt("mapLuoi", MapLuoi ? 1 : 0);
			break;
		}
	}

	public static void ShowMenuDoHoa()
	{
		MyVector myVector = new MyVector();
		myVector.addElement(new Command("logoPixel game: " + (HienThiLogo ? "ON" : "OFF"), getInstance(), 1, null));
		myVector.addElement(new Command("Background: " + (HienThiBackground ? "ON" : "OFF"), getInstance(), 2, null));
		myVector.addElement(new Command("Thông báo Boss: " + (isHuntingBoss ? "ON" : "OFF"), getInstance(), 3, null));
		myVector.addElement(new Command("Danh sách nhân vật: " + (isShowCharsInMap ? "ON" : "OFF"), getInstance(), 4, null));
		myVector.addElement(new Command("Địa hình dạng lưới: " + (MapLuoi ? "ON" : "OFF"), getInstance(), 5, null));
		GameCanvas.menu.startAt(myVector, 3);
	}

	public static void loadData()
	{
		HienThiLogo = Rms.loadRMSInt("saveLogo") == 1;
		HienThiBackground = Rms.loadRMSInt("saveBackground") == 1;
		isHuntingBoss = Rms.loadRMSInt("sanboss") != 0;
		isShowCharsInMap = Rms.loadRMSInt("showchar") != 0;
		MapLuoi = Rms.loadRMSInt("mapLuoi") == 1;
		NextMap.nextSuKien = Rms.loadRMSInt("nextMapTextSuKien") == 1;
		DrawFont = mFont.tahoma_7;
		if (mGraphics.zoomLevel == 4)
		{
			imgTheBai = Image.__createImage(Convert.FromBase64String(StringTheBai100x100));
		}
		else if (mGraphics.zoomLevel == 2)
		{
			imgTheBai = Image.__createImage(Convert.FromBase64String(StringTheBai70x70));
		}
		else
		{
			imgTheBai = Image.__createImage(Convert.FromBase64String(StringTheBai30x30));
		}
	}

	static GraphicsManagement()
	{
		paintBoxMobReduceCPU = false;
		paintInventoryReduceCPU = false;
		imgCheck = GameCanvas.loadImage("/mainImage/myTexture2dcheck.png");
		StringTheBai100x100 = "";
		StringTheBai70x70 = "";
		StringTheBai30x30 = "";
		HienThiBackground = true;
		isShowCharsInMap = true;
		isHuntingBoss = true;
		DrawFont = mFont.tahoma_7;
		logoCuongLe = "";
		logoPixel = "";
		Logo = "";
	}

	public string getOptionInfo(Item item)
	{
		if (item == null || !getLogicOPT(item) || item.template.type == 5 || (item.template.type > 5 && item.template.type != 32))
		{
			return string.Empty;
		}
		ItemOption[] itemOption = item.itemOption;
		ItemOption[] array = itemOption;
		ItemOption[] array2 = array;
		ItemOption[] array3 = array2;
		foreach (ItemOption itemOption2 in array3)
		{
			int id = itemOption2.optionTemplate.id;
			int param = itemOption2.param;
			switch (id)
			{
			case 50:
				return param + "% SĐ";
			case 77:
				return param + "% HP";
			case 80:
				return param + "% HP/30s";
			case 81:
				return param + "% KI/30s";
			case 94:
				return param + "% AD";
			case 95:
				return param + "% HM";
			case 96:
				return param + "% HK";
			case 97:
				return param + "% PST";
			case 100:
				return param + "% COIN";
			case 101:
				return param + "% EXP";
			case 103:
				return param + "% KI";
			}
		}
		return string.Empty;
	}

	private bool getLogicOPT(Item item)
	{
		if (item == null)
		{
			return false;
		}
		if (item.itemOption == null)
		{
			return false;
		}
		ItemOption[] itemOption = item.itemOption;
		for (int i = 0; i < itemOption.Length; i++)
		{
			switch (itemOption[i].optionTemplate.id)
			{
			case 50:
			case 77:
				return true;
			case 78:
			case 79:
			case 80:
			case 81:
				return true;
			case 94:
			case 95:
			case 96:
			case 97:
			case 100:
			case 101:
			case 103:
			case 104:
				return true;
			}
		}
		return false;
	}

	public void paintInfoOption(mGraphics g, Item item, int x, int y)
	{
		if (getLogicOPT(item))
		{
			mFont.tahoma_7_blue.drawString(g, getOptionInfo(item), x - mFont.tahoma_7_blue.getWidth(getOptionInfo(item)), y, mFont.LEFT);
		}
	}

